-- tedw_release_summary
VALUES (
'
<span style="background-color: #9D0208; color: white; font-weight: bold; font-size: 18px; padding: 5px; display: inline-block; text-decoration: underline;">Release Summary - 01/27/2025 :</span>
<h4 style="margin-top: 0;">This release includes the following:</h4>
<ol>
    <li>Enhancements - 5
        <ul>
			<li>Added state filings 1/25 release related 3 new columns for Home/Condo/Collections (fenced_pool_in, theft_or_loss_general_conditions_endorsement_in, animal_related_liability_endorsement_in). </li>
			<li>Backfilled wildfire protection data using information gathered from manual forms for the Redzone feed. </li>
			<li>Removed latitude and longitude columns from tmarine_boat_yacht_location and tquote_marine_boat_yacht_location tables. </li>
			<li>Updated IVANS Home data feed to incorporate introduction of granular coverages which gets rolled into AOP. </li>
			<li>Addition of uw_company_original_policy_effective_dt to tpolicy and tquote tables. </li>
		</ul>
    </li>
    <li>Bug tickets - 17
        <ul>
			<li>Resolved 1 ticket associated with updating 600 Home/Condo/Collections policies that were missing latitude and longitude columns. This is just a onetime datafix in EDW.</li>
			<li>Resolved 1 ticket associated with updating water damage limitation endorsement limit.</li>
			<li>Resolved 1 ticket associated with updating inspection date for ~7000 policies.</li>
			<li>Resolved 1 ticket associated with updating "water damage" loss type to "water" for multiple policies.</li>
			<li>Resolved 1 ticket associated with updating CoverageDOption to null where CoverageDOption = 0 and CoverageDPercentage > 0 for multiple policies.</li>
			<li>Resolved 1 ticket associated with updating logic in the hubspot broker feed stored procedure to exclude marine brokers.</li>
			<li>Resolved 1 ticket associated with updating logic in the tloss_history stored procedure to load include_in_rating_in column.</li>
			<li>Resolved 1 ticket associated with updating BCEGCreditPercent for one policy.</li>
			<li>Resolved 2 tickets associated with updating special characters from address fields affecting 2 policies for CLUE property feed.</li>
			<li>Resolved 7 tickets associated with repushing of IVANS policies.</li>
		</ul>
    </li>
</ol>
'
,'Yes'
,'2025-01-27'
,getdate()
,getdate()
)
;

